interface ShoppingListCardProps {
    note: Note;
    onSelectNote: (id: string) => void;
    onDeleteNote: (id: string) => void;
    onPinNote: (note: Note) => void;
    style: React.CSSProperties;
}

const ShoppingListCard: React.FC<ShoppingListCardProps> = ({ note, onSelectNote, onDeleteNote, onPinNote, style }) => {
    const formatCurrency = useCurrencyFormatter();

    const { listTotal, purchasedTotal, itemCount, progress } = useMemo(() => {
        if (!Array.isArray(note.content)) {
            return { listTotal: 0, purchasedTotal: 0, itemCount: 0, progress: 0 };
        }
        const items = note.content as ChecklistItem[];
        const listTotal = items.reduce((sum, item) => sum + (item.rate || 0) * (parseFloat(item.quantity) || 1), 0);
        const purchasedItems = items.filter(i => i.isPurchased);
        const purchasedTotal = purchasedItems.reduce((sum, item) => sum + (item.rate || 0) * (parseFloat(item.quantity) || 1), 0);
        const progress = items.length > 0 ? (purchasedItems.length / items.length) * 100 : 0;

        return { listTotal, purchasedTotal, itemCount: items.length, progress };
    }, [note.content]);

    return (
        <div 
            onClick={() => onSelectNote(note.id)} 
            className={`p-4 rounded-xl cursor-pointer transition-colors glass-card stagger-delay ${note.isPinned ? 'pinned' : ''}`}
            style={style}
        >
            <div className="flex justify-between items-start">
                <h3 className="text-lg font-bold text-primary">{note.title || 'Untitled Shopping List'}</h3>
                <div className="flex items-center gap-2 flex-shrink-0">
                    <button 
                        onClick={(e) => { e.stopPropagation(); onPinNote(note); }} 
                        className={`p-2 rounded-md transition-colors ${note.isPinned ? 'bg-sky-500/80 text-white' : 'bg-slate-800/60 hover:bg-slate-700/60 text-sky-300'}`}
                        title={note.isPinned ? 'Unpin' : 'Pin'}
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 24" fill="currentColor">
                            <path transform="rotate(45 12 12)" d="M16,12V4H17V2H7V4H8V12L6,14V16H11.5V22H12.5V16H18V14L16,12Z" />
                        </svg>
                    </button>
                    <button onClick={(e) => { e.stopPropagation(); onSelectNote(note.id); }} className="text-sm text-sky-400 hover:text-sky-300">Edit</button>
                    <button onClick={(e) => { e.stopPropagation(); onDeleteNote(note.id); }} className="text-sm text-rose-400 hover:text-rose-300">Delete</button>
                </div>
            </div>
            <p className="text-xs text-secondary mt-1">{itemCount} items • Updated: {new Date(note.updatedAt).toLocaleDateString()}</p>
            <div className="w-full bg-subtle rounded-full h-1.5 mt-3">
                <div 
                    className="bg-emerald-500 h-1.5 rounded-full" 
                    style={{ width: `${progress}%` }}
                ></div>
            </div>
            <div className="flex justify-between text-sm mt-3">
                <div>
                    <p className="text-secondary">Purchased</p>
                    <p className="font-semibold text-emerald-400">{formatCurrency(purchasedTotal)}</p>
                </div>
                <div className="text-right">
                    <p className="text-secondary">List Total</p>
                    <p className="font-semibold text-primary">{formatCurrency(listTotal)}</p>
                </div>
            </div>
        </div>
    );
};


interface NoteListViewProps {
    onSelectNote: (id: string) => void;
    onAddNote: (type: 'note' | 'checklist', tripId?: string) => void;
    onDeleteNote: (id: string) => void;
    onPinNote: (note: Note) => void;
    openModal: (name: ActiveModal, props?: Record<string, any>) => void;
}

const NoteListView: React.FC<NoteListViewProps> = ({ onSelectNote, onAddNote, onDeleteNote, onPinNote, openModal }) => {
    const dataContext = useContext(AppDataContext);
    const [searchQuery, setSearchQuery] = useState('');
    const [viewOptions, setViewOptions] = useState<AppliedViewOptions>({
        sort: { key: 'updatedAt', direction: 'desc' },
        filters: {}
    });
    const [activeTab, setActiveTab] = useState<'notes' | 'lists'>('notes');

    if (!dataContext) return null;
    const { notes = [], trips = [] } = dataContext;

    const tripMap = useMemo(() => new Map(trips.map(t => [t.id, t.name])), [trips]);

    const { pinnedItems, regularNotes, shoppingLists } = useMemo(() => {
        const pinned: Note[] = [];
        const regulars: Note[] = [];
        const lists: Note[] = [];

        for (const note of notes) {
            const matchesSearch = note.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                                  (typeof note.content === 'string' && note.content.toLowerCase().includes(searchQuery.toLowerCase()));

            if (matchesSearch) {
                if (note.isPinned) {
                    pinned.push(note);
                } else if (note.type === 'note') {
                    regulars.push(note);
                } else {
                    lists.push(note);
                }
            }
        }

        const { key, direction } = viewOptions.sort;
        const sortFn = (a: Note, b: Note) => {
            let comparison = 0;
            switch(key) {
                case 'title':
                    comparison = a.title.localeCompare(b.title);
                    return direction === 'asc' ? comparison : -comparison;
                case 'createdAt':
                    comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
                    break;
                case 'updatedAt':
                default:
                    comparison = new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime();
                    break;
            }
            return direction === 'desc' ? -comparison : comparison;
        };

        pinned.sort(sortFn);
        regulars.sort(sortFn);
        lists.sort(sortFn);

        return { pinnedItems: pinned, regularNotes: regulars, shoppingLists: lists };
    }, [notes, searchQuery, viewOptions]);

    const currentList = activeTab === 'notes' ? regularNotes : shoppingLists;
    const pinnedForTab = pinnedItems.filter(p => activeTab === 'notes' ? p.type === 'note' : p.type === 'checklist');

    const viewOptionsConfig: ViewOptions = {
        sortOptions: [ { key: 'updatedAt', label: 'Last Updated' }, { key: 'createdAt', label: 'Date Created'}, { key: 'title', label: 'Title' }, ],
        filterOptions: []
    };
    const isViewOptionsApplied = viewOptions.sort.key !== 'updatedAt' || viewOptions.sort.direction !== 'desc';

    const getSnippet = (note: Note) => {
        if (typeof note.content === 'string') {
            return note.content.substring(0, 100);
        }
        if (Array.isArray(note.content) && note.content.length > 0) {
            return note.content.slice(0, 3).map(item => `• ${item.name}`).join(', ');
        }
        return 'No content';
    }

    // Fix: Explicitly define return type as React.ReactNode and cast style to any to satisfy the compiler.
    const renderNoteItem = (note: Note, index: number): React.ReactNode => {
      if (note.type === 'checklist') {
        return <ShoppingListCard key={note.id} note={note} onSelectNote={onSelectNote} onDeleteNote={onDeleteNote} onPinNote={onPinNote} style={{'--stagger-index': index} as any} />
      }

      return (
        <div key={note.id} onClick={() => onSelectNote(note.id)} className={`note-list-item ${note.isPinned ? 'pinned' : ''} stagger-delay`} style={{'--stagger-index': index} as any}>
            <div className="note-list-item-icon">{note.icon || '📝'}</div>
            <div className="note-list-item-content">
                <p className="note-list-item-title">{note.title || 'Untitled'}</p>
                <p className="note-list-item-snippet">{getSnippet(note)}</p>
                {note.tripId && <span className="text-xs text-amber-400 bg-amber-900/50 px-2 py-0.5 rounded-full mt-2 inline-block">✈️ {tripMap.get(note.tripId)}</span>}
            </div>
            <div className="note-list-item-actions">
                <button 
                    onClick={(e) => { e.stopPropagation(); onPinNote(note); }} 
                    className={`pin-button ${note.isPinned ? 'pinned' : ''}`}
                    title={note.isPinned ? 'Unpin' : 'Pin'}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 24" fill="currentColor">
                        <path transform="rotate(45 12 12)" d="M16,12V4H17V2H7V4H8V12L6,14V16H11.5V22H12.5V16H18V14L16,12Z" />
                    </svg>
                </button>
                <button onClick={(e) => { e.stopPropagation(); onDeleteNote(note.id); }} className="p-2 text-rose-400/60 hover:text-rose-400 rounded-full" title="Delete">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
            </div>
        </div>
      )
    };

    return (
        <div className="h-full flex flex-col">
            <div className="p-4 border-b border-divider flex-shrink-0 flex justify-between items-center">
                <h2 className="text-2xl font-bold text-primary">Notes & Lists</h2>
                <button onClick={() => openModal('viewOptions', { options: viewOptionsConfig, currentValues: viewOptions, onApply: setViewOptions })} className="button-secondary text-sm p-2 flex items-center gap-2 relative rounded-full aspect-square">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M3 4h18M3 10h12M3 16h6" /></svg>
                    {isViewOptionsApplied && <div className="absolute -top-0.5 -right-0.5 w-2 h-2 bg-emerald-400 rounded-full ring-2 ring-[var(--color-bg-app)]"></div>}
                </button>
            </div>
            <div className="p-4 flex-shrink-0 border-b border-divider">
                <input type="text" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder="Search..." className="input-base w-full p-2 rounded-full" />
            </div>
            <div className="notes-tabs-container">
                <button onClick={() => setActiveTab('notes')} className={`notes-tab-button ${activeTab === 'notes' ? 'active' : ''}`}>Notes ({regularNotes.length})</button>
                <button onClick={() => setActiveTab('lists')} className={`notes-tab-button ${activeTab === 'lists' ? 'active' : ''}`}>Shopping Lists ({shoppingLists.length})</button>
            </div>
            <div className="flex-grow overflow-y-auto">
                {pinnedForTab.length > 0 && (
                    <div className="pinned-notes-section">
                        <h3 className="text-sm font-semibold text-sky-400 mb-2">Pinned</h3>
                        <div className="space-y-3">{pinnedForTab.map(renderNoteItem)}</div>
                    </div>
                )}
                <div className="p-4 space-y-3">
                    {currentList.length > 0 ? (
                        currentList.map(renderNoteItem)
                    ) : (
                         <div className="pt-8">
                            <EmptyState 
                                icon={activeTab === 'notes' ? '📝' : '✅'}
                                title={searchQuery ? "No Results Found" : `No ${activeTab === 'notes' ? 'Notes' : 'Lists'} Yet`}
                                message={searchQuery ? `No items matched your search for "${searchQuery}".` : `Create your first ${activeTab === 'notes' ? 'note' : 'list'} to keep track of important information.`}
                            />
                        </div>
                    )}
                </div>
            </div>
             <div className="p-4 border-t border-divider flex-shrink-0">
                <button onClick={() => openModal('addNoteType')} className="button-primary w-full py-2">+ Create New</button>
            </div>
        </div>
    );
}


interface NotesScreenProps {
  noteId: string | null;
  onCreateExpense: (list: Note) => void;
  openModal: (name: ActiveModal, props?: Record<string, any>) => void;
  onDeleteItem: (id: string, itemType: ItemType) => void;
  onNavigate: (screen: ActiveScreen, modal?: ActiveModal, props?: Record<string, any>) => void;
}

export const NotesScreen: React.FC<NotesScreenProps> = (props) => {
  const { noteId, onCreateExpense, openModal, onDeleteItem, onNavigate } = props;
  const dataContext = useContext(AppDataContext);

  if (!dataContext) return <div>Loading...</div>;

  const { notes, setNotes } = dataContext;

  const selectedNote = useMemo(() => (notes || []).find(note => note.id === noteId), [notes, noteId]);

  const handleBackToLists = () => onNavigate('notes');

  const handleAddNote = (type: 'note' | 'checklist', tripId?: string) => {
    const now = new Date().toISOString();
    const newNote: Note = {
      id: self.crypto.randomUUID(),
      title: `Untitled ${type === 'note' ? 'Note' : 'Checklist'}`,
      content: type === 'note' ? '' : [],
      type: type,
      createdAt: now,
      updatedAt: now,
      tripId: tripId,
      isPinned: false,
      icon: type === 'note' ? '📝' : '✅',
    };
    setNotes(prev => [...(prev || []), newNote]);
    onNavigate('notes', undefined, { noteId: newNote.id });
  };

  const handleSaveNote = (updatedNote: Note) => {
    setNotes(prev => (prev || []).map(note => note.id === updatedNote.id ? { ...updatedNote, updatedAt: new Date().toISOString() } : note));
  };

  const handlePinNote = (noteToPin: Note) => {
    handleSaveNote({ ...noteToPin, isPinned: !noteToPin.isPinned });
  };

  const handleDeleteNote = (id: string) => {
      onDeleteItem(id, 'note');
      if (noteId === id) {
          onNavigate('notes');
      }
  }

  if (selectedNote) {
    if (selectedNote.type === 'checklist') {
        return <ChecklistDetailView list={selectedNote} onSave={handleSaveNote} onBack={handleBackToLists} onCreateExpense={handleCreateExpenseFromList} openModal={openModal} />;
    }
    return <NoteDetailView note={selectedNote} onSave={handleSaveNote} onBack={handleBackToLists} openModal={openModal} />;
  }
  return <NoteListView onSelectNote={(id) => onNavigate('notes', undefined, { noteId: id })} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} onPinNote={handlePinNote} openModal={openModal} />;
};

import React, { useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import useLocalStorage from './useLocalStorage';
import { 
  AppState, Profile, Settings, Account, Transaction, TransactionType, Category, Goal, Budget, RecurringTransaction, InvestmentHolding, Contact, ContactGroup, Trip, TripExpense, TripMessage, Shop, ShopProduct, ShopSale, ShopEmployee, ShopShift, Refund, Debt, Note, ItemType, TrustBinItem, GlossaryEntry, Challenge, UserStreak, ParsedTransactionData, Sender, Invoice, InvoiceStatus,
  AccountType,
  FinancialProfile,
  CalendarEvent,
  Settlement,
  Priority,
  supabase,
  User,
  Session
} from '../types';
import { AppDataContext, DEFAULT_SETTINGS } from '../contexts/SettingsContext';
import { DEFAULT_CATEGORIES } from '../utils/categories';
import { db } from '../services/supabaseService';
import { DEFAULT_GLOSSARY_ENTRIES } from '../utils/glossary';

export const AppDataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [isCloudSynced, setIsCloudSynced] = useState(false);

  // Local-first persistence
  const [settings, setSettings] = useLocalStorage<Settings>('settings', DEFAULT_SETTINGS);
  const [financialProfile, setFinancialProfile] = useLocalStorage<FinancialProfile>('financialProfile', { monthlySalary: 0, monthlyRent: 0, monthlyEmi: 0, emergencyFundGoal: 0 });
  const [accounts, setAccounts] = useLocalStorage<Account[]>('accounts', []);
  const [categories, setCategories] = useLocalStorage<Category[]>('categories', DEFAULT_CATEGORIES);
  const [transactions, setTransactions] = useLocalStorage<Transaction[]>('transactions', []);
  const [budgets, setBudgets] = useLocalStorage<Budget[]>('budgets', []);
  const [goals, setGoals] = useLocalStorage<Goal[]>('goals', []);
  const [recurringTransactions, setRecurringTransactions] = useLocalStorage<RecurringTransaction[]>('recurringTransactions', []);
  const [investmentHoldings, setInvestmentHoldings] = useLocalStorage<InvestmentHolding[]>('investmentHoldings', []);
  const [contacts, setContacts] = useLocalStorage<Contact[]>('contacts', []);
  const [contactGroups, setContactGroups] = useLocalStorage<ContactGroup[]>('contactGroups', []);
  const [trips, setTrips] = useLocalStorage<Trip[]>('trips', []);
  const [tripExpenses, setTripExpenses] = useLocalStorage<TripExpense[]>('tripExpenses', []);
  const [tripMessages, setTripMessages] = useLocalStorage<TripMessage[]>('tripMessages', []);
  const [shops, setShops] = useLocalStorage<Shop[]>('shops', []);
  const [shopProducts, setShopProducts] = useLocalStorage<ShopProduct[]>('shopProducts', []);
  const [shopSales, setShopSales] = useLocalStorage<ShopSale[]>('shopSales', []);
  const [shopEmployees, setShopEmployees] = useLocalStorage<ShopEmployee[]>('shopEmployees', []);
  const [shopShifts, setShopShifts] = useLocalStorage<ShopShift[]>('shopShifts', []);
  const [refunds, setRefunds] = useLocalStorage<Refund[]>('refunds', []);
  const [settlements, setSettlements] = useLocalStorage<Settlement[]>('settlements', []);
  const [debts, setDebts] = useLocalStorage<Debt[]>('debts', []);
  const [notes, setNotes] = useLocalStorage<Note[]>('notes', []);
  const [glossaryEntries, setGlossaryEntries] = useLocalStorage<GlossaryEntry[]>('glossaryEntries', DEFAULT_GLOSSARY_ENTRIES);
  const [unlockedAchievements, setUnlockedAchievements] = useLocalStorage<any[]>('unlockedAchievements', []);
  const [challenges, setChallenges] = useLocalStorage<Challenge[]>('challenges', []);
  const [streaks, setStreaks] = useLocalStorage<UserStreak>('streaks', { currentStreak: 0, longestStreak: 0, lastActivityDate: '', streakFreezes: 3 });
  const [invoices, setInvoices] = useLocalStorage<Invoice[]>('invoices', []);
  const [payees, setPayees] = useLocalStorage<any[]>('payees', []);
  const [senders, setSenders] = useLocalStorage<any[]>('senders', []);
  const [customCalendarEvents, setCustomCalendarEvents] = useLocalStorage<CalendarEvent[]>('customCalendarEvents', []);
  const [trustBin, setTrustBin] = useLocalStorage<TrustBinItem[]>('trustBin', []);

  const [selectedAccountIds, setSelectedAccountIds] = useState(['all']);

  // AUTH STATE LISTENER
  useEffect(() => {
    // Fix: In Supabase v2, getSession is an async method on supabase.auth.
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
    });

    // Fix: onAuthStateChange returns an object containing subscription in v2.
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (!session) setIsCloudSynced(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  // CLOUD SYNC ENGINE
  useEffect(() => {
    if (!user || isCloudSynced) return;

    const syncFromCloud = async () => {
        setIsLoading(true);
        try {
            // Parallel fetch for all modules
            const [
                cloudAccounts, cloudTransactions, cloudGoals, cloudBudgets, cloudSettings
            ] = await Promise.all([
                db.fetchAll<Account>('accounts', user.id),
                db.fetchAll<Transaction>('transactions', user.id),
                db.fetchAll<Goal>('goals', user.id),
                db.fetchAll<Budget>('budgets', user.id),
                db.fetchAll<Settings>('settings', user.id)
            ]);

            // Simple conflict resolution: Cloud wins if data exists
            if (cloudAccounts.length > 0) setAccounts(cloudAccounts);
            if (cloudTransactions.length > 0) setTransactions(cloudTransactions);
            if (cloudGoals.length > 0) setGoals(cloudGoals);
            if (cloudBudgets.length > 0) setBudgets(cloudBudgets);
            if (cloudSettings.length > 0) setSettings(cloudSettings[0]);

            setIsCloudSynced(true);
        } catch (e) {
            console.error("Cloud sync failed", e);
        } finally {
            setIsLoading(false);
        }
    };

    syncFromCloud();
  }, [user, isCloudSynced]);

  // WRAPPERS FOR DATABASE PERSISTENCE
  const persist = useCallback(async (table: string, item: any) => {
    if (user) {
        try { await db.upsert(table, item, user.id); } catch (e) { console.error(`Failed to sync ${table}`, e); }
    }
  }, [user]);

  const removeCloud = useCallback(async (table: string, id: string) => {
    if (user) {
        try { await db.delete(table, id, user.id); } catch (e) { console.error(`Failed to delete from cloud ${table}`, e); }
    }
  }, [user]);

  // Re-define CRUD methods to use sync
  const onSaveManual = useCallback(async (transaction: Transaction) => {
    setTransactions(prev => [transaction, ...prev]);
    persist('transactions', transaction);
  }, [setTransactions, persist]);

  const onAddAccount = useCallback(async (name: string, accountType: AccountType, currency: string, creditLimit?: number) => {
    const newAccount: Account = { id: self.crypto.randomUUID(), name, accountType, currency, creditLimit };
    setAccounts(prev => [...prev, newAccount]);
    persist('accounts', newAccount);
  }, [setAccounts, persist]);

  const deleteItem = useCallback(async (id: string, itemType: ItemType) => {
    const setters: any = { transaction: setTransactions, account: setAccounts, goal: setGoals };
    const tables: any = { transaction: 'transactions', account: 'accounts', goal: 'goals' };

    if (setters[itemType]) {
        setters[itemType]((prev: any[]) => prev.filter((i: any) => i.id !== id));
        removeCloud(tables[itemType], id);
    }
  }, [user, removeCloud, setTransactions, setAccounts, setGoals]);

  const value = {
    isLoading, user, isCloudSynced,
    settings, transactions, accounts, categories, budgets, goals, recurringTransactions, investmentHoldings, contacts, contactGroups, trips, tripExpenses, tripMessages, shops, shopProducts, shopSales, shopEmployees, shopShifts, refunds, settlements, debts, notes, glossaryEntries, unlockedAchievements, challenges, streaks, invoices, payees, senders,
    customCalendarEvents, financialProfile, trustBin,
    setSettings, setTransactions, setAccounts, setGoals, setBudgets, setRecurringTransactions, setChallenges, setRefunds, setDebts, setNotes, setGlossaryEntries, setUnlockedAchievements, setInvoices, setPayees, setSenders, setCustomCalendarEvents, setFinancialProfile, setTrustBin,
    onSaveManual, onAddAccount, deleteItem,
    selectedAccountIds, setSelectedAccountIds,
  };

  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 500);
    return () => clearTimeout(timer);
  }, []);

  return <AppDataContext.Provider value={value as any}>{children}</AppDataContext.Provider>;
};

export const useAppContext = () => {
  const context = useContext(AppDataContext);
  if (context === undefined) throw new Error('useAppContext must be used within an AppDataProvider');
  return context;
};

import { supabase } from '../types';

export const db = {
    async fetchAll<T>(table: string, userId: string): Promise<T[]> {
        const { data, error } = await supabase
            .from(table)
            .select('*')
            .eq('user_id', userId);
        if (error) throw error;
        return data as T[];
    },

    async upsert<T extends { id: string }>(table: string, item: T, userId: string): Promise<T> {
        const payload = { ...item, user_id: userId };
        const { data, error } = await supabase
            .from(table)
            .upsert(payload)
            .select()
            .single();
        if (error) throw error;
        return data as T;
    },

    async delete(table: string, id: string, userId: string): Promise<void> {
        const { error } = await supabase
            .from(table)
            .delete()
            .eq('id', id)
            .eq('user_id', userId);
        if (error) throw error;
    },

    async bulkUpsert<T>(table: string, items: T[], userId: string): Promise<void> {
        const payload = items.map(item => ({ ...item, user_id: userId }));
        const { error } = await supabase
            .from(table)
            .upsert(payload);
        if (error) throw error;
    }
};

